// Clear user cache and test profile endpoint
export const clearUserCacheAndTest = async () => {
  console.log('🧹 Clearing user cache...');

  // Clear all localStorage and sessionStorage
  localStorage.clear();
  sessionStorage.clear();

  console.log('✅ Cache cleared');

  // Wait a moment for cache to clear
  await new Promise(resolve => setTimeout(resolve, 1000));

  console.log('🔄 Reloading page...');
  window.location.reload();
};

// Test profile endpoint after login
export const testUserProfile = async () => {
  console.log('🧪 Testing user profile endpoint...');

  const token = localStorage.getItem('token');
  if (!token) {
    console.log('❌ No token found. Please login first.');
    return;
  }

  try {
    const response = await fetch('http://localhost:8083/api/users/profile', {
      headers: { 
        'Authorization': `Bearer ${token}`,
        'Content-Type': 'application/json'
      }
    });

    if (response.ok) {
      const data = await response.json();
      console.log('✅ Profile endpoint response:', data);
      console.log('📊 User Status:');
      console.log('  - Can submit complaints:', data.canSubmitComplaints);
      console.log('  - Is banned:', data.isBanned);
      console.log('  - Strike count:', data.strikeCount);
      console.log('  - Ban reason:', data.banReason);
      console.log('  - Enabled:', data.enabled);

      // Check if user should be able to file complaints
      if (data.canSubmitComplaints && !data.isBanned) {
        console.log('✅ User should be able to file complaints!');
      } else {
        console.log('❌ User is still blocked from filing complaints');
        console.log('🔧 Check these values:');
        console.log('  - canSubmitComplaints:', data.canSubmitComplaints);
        console.log('  - isBanned:', data.isBanned);
      }
    } else {
      console.log('❌ Profile endpoint failed:', response.status, response.statusText);
    }
  } catch (error) {
    console.log('❌ Error testing profile:', error);
  }
};

// Force refresh user data in dashboard
export const refreshUserData = () => {
  console.log('🔄 Refreshing user data...');

  // Trigger a re-fetch of user data
  if (window.location.pathname.includes('/dashboard')) {
    // If on dashboard, trigger data refresh
    window.dispatchEvent(new CustomEvent('refreshUserData'));
  } else {
    // Navigate to dashboard
    window.location.href = '/dashboard';
  }
};

// Expose to console for easy access
if (typeof window !== 'undefined') {
  window.clearUserCache = clearUserCacheAndTest;
  window.testProfile = testUserProfile;
  window.refreshUserData = refreshUserData;

  console.log('🔧 User cache utilities exposed to console:');
  console.log('  - clearUserCache() - Clear cache and reload');
  console.log('  - testProfile() - Test profile endpoint');
  console.log('  - refreshUserData() - Refresh user data');
}
